SELECT employees.name, employees.email, employees.designation, schools.school_name
FROM employees
JOIN schools ON schools.dean_id = employees.employee_id;

SELECT * 
FROM employees 
WHERE school_id = (
    SELECT school_id FROM schools WHERE school_name = 'School of Engineering - Chennai'
) 
AND employee_id IN (
    SELECT employee_id FROM user_accounts 
    WHERE role_id = (
        SELECT role_id FROM user_roles WHERE role_name = 'HR Admin'
    )
);

SELECT name, designation
FROM employees
WHERE status = 'active' AND campus = 'Campus 1';

SELECT employees.name, employees.designation, schools.school_name
FROM employees
JOIN schools ON employees.school_id = schools.school_id;

SELECT s.*
FROM salary_records AS s
WHERE s.net_salary > (SELECT AVG(net_salary) AS avg_net_salary FROM salary_records);

SELECT name 
FROM employees 
WHERE employee_id IN (SELECT employee_id FROM salary_records);

SELECT e.name, d.department_name
FROM employees e
JOIN departments d ON e.employee_id = d.head_of_department;

SELECT employee_id, benefit_type, SUM(benefit_amount) AS total_benefit
FROM employee_benefits
GROUP BY employee_id, benefit_type;
